export type KnowledgeCheck = {
  question: string;
  answers: string[];
  correct: number;
  explanation: string;
};

export type CourseLesson = {
  id: string;
  title: string;
  minutes: number;
  objectives: string[];
  prerequisites: string[];
  concepts: { title: string; paragraphs: string[] }[];
  terms: [string, string][];
  method: string[];
  example: { title: string; scenario: string; steps: string[]; result: string };
  mistakes: string[];
  check: KnowledgeCheck;
  practice: { prompt: string; hint: string; answer: string };
  summary: string[];
};

export type CourseModule = {
  id: number;
  title: string;
  summary: string;
  minutes: number;
  difficulty: "Beginner" | "Intermediate" | "Advanced";
  topics: string[];
  lessons: [CourseLesson, CourseLesson];
};

const lesson = (value: CourseLesson) => value;

