export const allLessons = courseModules.flatMap((module) =>
  module.lessons.map((item, lessonIndex) => ({ ...item, module, lessonIndex })),
);

export function findLesson(pathname: string) {
  const slug = pathname.split("?")[0].split("/").filter(Boolean).at(-1);
  return allLessons.find((item) => item.id === slug) ?? allLessons[0];
}
